import React, { forwardRef } from "react";
import { QRCodeCanvas } from "qrcode.react";

const Badge = forwardRef(({ youth }, ref) => {
  if (!youth) return null;

  return (
    <div
      ref={ref}
      style={{
        width: "320px",
        border: "3px solid #2c3e50",
        borderRadius: "10px",
        padding: "20px",
        textAlign: "center",
        fontFamily: "Arial",
        background: "white",
      }}
    >
      <h2 style={{ margin: "5px", color: "#2c3e50" }}>
        New Apostolic Church
      </h2>

      <p style={{ margin: "5px", color: "#555" }}>
        Youth Convention
      </p>

      <hr />

      <h2 style={{ margin: "10px 0" }}>
        {youth.fullName}
      </h2>

      <p>{youth.congregation}</p>

      <p>{youth.phone}</p>

      <div style={{ marginTop: "15px" }}>
        <QRCodeCanvas value={youth._id} size={120} />
      </div>

      <p style={{ fontSize: "12px", marginTop: "10px" }}>
        Scan for check-in
      </p>
    </div>
  );
});

export default Badge;
